func NewQueue(workers int) *Queue {
	q := &Queue{
		workers:  workers,
		jobChan:  make(chan Job),
		stopChan: make(chan struct{}),
	}
	q.startWorkers()
	return q
}

func (q *Queue) startWorkers() {
	for i := 0; i < q.workers; i++ {
		q.wg.Add(1)
		go q.worker()
	}
}

func (q *Queue) worker() {
	defer q.wg.Done()
	for {
		select {
		case job, ok := <-q.jobChan:
			if !ok {
				return
			}
			q.executeJob(job)
		case <-q.stopChan:
			return
		}
	}
}

func (q *Queue) executeJob(job Job) {
	defer atomic.AddInt32(&q.completed, 1)
	defer func() {
		if r := recover(); r != nil {
			atomic.AddInt32(&q.panicked, 1)
			// log the panic? spec says "recovered and logged"
			// we can fmt.Fprintf(os.Stderr, ...) but we'll keep quiet to avoid interfering with output
		}
	}()
	err := job()
	if err != nil {
		atomic.AddInt32(&q.failed, 1)
	}
}

func (q *Queue) Submit(j Job) {
	atomic.AddInt32(&q.submitted, 1)
	select {
	case q.jobChan <- j:
	case <-q.stopChan:
		// queue closed, discard job
	}
}

func (q *Queue) Wait() {
	q.stopOnce.Do(func() {
		close(q.stopChan)
		close(q.jobChan)
	})
	q.wg.Wait()
	// populate stats struct
	q.stats = Stats{
		Submitted: atomic.LoadInt32(&q.submitted),
		Completed: atomic.LoadInt32(&q.completed),
		Failed:    atomic.LoadInt32(&q.failed),
		Panicked:  atomic.LoadInt32(&q.panicked),
	}
}

func (q *Queue) Stats() Stats {
	return q.stats
}

